import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorDotsThree } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { breadcrumbEllipsisVariants } from './breadcrumb.variants';

@Component({
  selector: 'hb-breadcrumb-ellipsis, [hb-breadcrumb-ellipsis]',
  imports: [NgIcon],
  template: `<ng-icon name="phosphorDotsThree" />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  viewProviders: [provideIcons({ phosphorDotsThree })],
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'breadcrumb-ellipsis'",
    'aria-hidden': 'true',
    role: 'presentation',
  },
  exportAs: 'hbBreadcrumbEllipsis',
})
export class HbBreadcrumbEllipsisComponent {
  readonly class = input<ClassValue>('');
  protected readonly classes = computed(() => cn(breadcrumbEllipsisVariants(), this.class()));
}

import { NgTemplateOutlet } from '@angular/common';
import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  ElementRef,
  inject,
  input,
  output,
  ViewEncapsulation,
} from '@angular/core';
import { type Params, RouterLink } from '@angular/router';

import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorCaretRight, phosphorDotsThree } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbMenuImports } from '{{alias}}/menu';
import { HbBreadcrumbComponent } from './breadcrumb.component';
import { HbBreadcrumbEllipsisComponent } from './breadcrumb-ellipsis.component';
import {
  breadcrumbEllipsisVariants,
  breadcrumbItemVariants,
  breadcrumbLinkVariants,
  breadcrumbSeparatorVariants,
} from './breadcrumb.variants';

@Component({
  selector: 'hb-breadcrumb-item, [hb-breadcrumb-item]',
  imports: [NgIcon, NgTemplateOutlet, RouterLink, HbMenuImports],
  template: `
    <ng-template #label><ng-content /></ng-template>

    @if (autoEllipsis()) {
      <button
        type="button"
        [class]="ellipsisClasses"
        [hbMenuTriggerFor]="collapsedMenu"
        aria-label="Show collapsed breadcrumbs"
      >
        <ng-icon name="phosphorDotsThree" />
      </button>
    } @else if (isEllipsis()) {
      <ng-container [ngTemplateOutlet]="label" />
    } @else if (hasLink()) {
      <a
        [class]="linkClasses()"
        [routerLink]="hbLink()"
        [queryParams]="hbQueryParams()"
        [fragment]="hbFragment()"
        (click)="hbClick.emit()"
      >
        <ng-container [ngTemplateOutlet]="label" />
      </a>
    } @else if (hbHref()) {
      <a [class]="linkClasses()" [href]="hbHref()" (click)="hbClick.emit()">
        <ng-container [ngTemplateOutlet]="label" />
      </a>
    } @else {
      <span [class]="linkClasses()" [attr.aria-current]="hbCurrent() ? 'page' : null">
        <ng-container [ngTemplateOutlet]="label" />
      </span>
    }

    @if (!hidden() && !isLast()) {
      <span [class]="separatorClasses" aria-hidden="true" role="presentation">
        @if (root.separatorTemplate(); as tpl) {
          <ng-container [ngTemplateOutlet]="tpl" />
        } @else if (root.hbSeparator()) {
          {{ root.hbSeparator() }}
        } @else {
          <ng-icon name="phosphorCaretRight" />
        }
      </span>
    }

    <ng-template #collapsedMenu>
      <hb-menu class="min-w-40">
        @for (item of root.collapsedItems(); track $index) {
          @if (item.hasLink()) {
            <a
              hb-menu-item
              [routerLink]="item.hbLink()"
              [queryParams]="item.hbQueryParams()"
              [fragment]="item.hbFragment()"
            >
              {{ item.label() }}
            </a>
          } @else if (item.hbHref()) {
            <a hb-menu-item [href]="item.hbHref()">{{ item.label() }}</a>
          } @else {
            <button hb-menu-item type="button" (hbSelect)="item.hbClick.emit()">
              {{ item.label() }}
            </button>
          }
        }
      </hb-menu>
    </ng-template>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  viewProviders: [provideIcons({ phosphorCaretRight, phosphorDotsThree })],
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'breadcrumb-item'",
    '[style.display]': "display() === 'hidden' ? 'none' : null",
  },
  exportAs: 'hbBreadcrumbItem',
})
export class HbBreadcrumbItemComponent {
  protected readonly root = inject(HbBreadcrumbComponent);
  private readonly ellipsisContent = contentChild(HbBreadcrumbEllipsisComponent);

  readonly hbLink = input<string | string[] | null>(null);
  readonly hbQueryParams = input<Params | null | undefined>(undefined);
  readonly hbFragment = input<string | undefined>(undefined);
  readonly hbHref = input<string>('');
  readonly hbCurrent = input(false, { transform: booleanAttribute });
  readonly hbLabel = input<string>('');
  readonly class = input<ClassValue>('');

  readonly hbClick = output<void>();

  private readonly capturedLabel = (inject(ElementRef).nativeElement as HTMLElement).textContent?.trim() ?? '';
  readonly label = computed(() => this.hbLabel() || this.capturedLabel);
  readonly display = computed(() => this.root.itemDisplay(this));
  protected readonly hidden = computed(() => this.display() === 'hidden');
  protected readonly autoEllipsis = computed(() => this.display() === 'ellipsis');
  protected readonly isEllipsis = computed(() => this.ellipsisContent() != null);
  protected readonly isLast = computed(() => this.root.isLast(this));

  readonly hasLink = computed(() => {
    const link = this.hbLink();
    return Array.isArray(link) ? link.length > 0 : !!link;
  });

  protected readonly classes = computed(() => cn(breadcrumbItemVariants(), this.class()));
  protected readonly linkClasses = computed(() =>
    breadcrumbLinkVariants({ current: this.hbCurrent() }),
  );
  protected readonly separatorClasses = cn(breadcrumbSeparatorVariants());
  protected readonly ellipsisClasses = cn(breadcrumbEllipsisVariants());
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  contentChildren,
  Directive,
  input,
  TemplateRef,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbBreadcrumbItemComponent } from './breadcrumb-item.component';
import {
  breadcrumbListVariants,
  breadcrumbVariants,
  type HbBreadcrumbAlign,
  type HbBreadcrumbSize,
  type HbBreadcrumbWrap,
} from './breadcrumb.variants';

@Directive({ selector: '[hbBreadcrumbSeparator]' })
export class HbBreadcrumbSeparatorDirective {}

@Component({
  selector: 'hb-breadcrumb, [hb-breadcrumb]',
  template: `
    <nav aria-label="breadcrumb" [class]="navClasses()">
      <ol [class]="listClasses()">
        <ng-content />
      </ol>
    </nav>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[attr.data-slot]': "'breadcrumb'" },
  exportAs: 'hbBreadcrumb',
})
export class HbBreadcrumbComponent {
  readonly hbSize = input<HbBreadcrumbSize>('md');
  readonly hbAlign = input<HbBreadcrumbAlign>('start');
  readonly hbWrap = input<HbBreadcrumbWrap>('wrap');
  readonly hbSeparator = input<string>('');
  readonly hbMaxItems = input<number | null>(null);
  readonly class = input<ClassValue>('');

  readonly items = contentChildren(HbBreadcrumbItemComponent);
  readonly separatorTemplate = contentChild(HbBreadcrumbSeparatorDirective, { read: TemplateRef });

  protected readonly navClasses = computed(() =>
    cn(breadcrumbVariants({ size: this.hbSize() }), this.class()),
  );
  protected readonly listClasses = computed(() =>
    breadcrumbListVariants({ align: this.hbAlign(), wrap: this.hbWrap() }),
  );

  itemDisplay(item: HbBreadcrumbItemComponent): 'visible' | 'ellipsis' | 'hidden' {
    const list = this.items();
    const total = list.length;
    const max = this.hbMaxItems();
    if (max == null || max <= 0 || total <= max) return 'visible';

    const index = list.indexOf(item);
    const keepEnd = max - 1;
    const firstCollapsed = 1;
    const lastCollapsed = total - keepEnd - 1;
    if (index <= 0 || index > lastCollapsed) return 'visible';
    if (index === firstCollapsed) return 'ellipsis';
    return 'hidden';
  }

  isLast(item: HbBreadcrumbItemComponent): boolean {
    return this.items().at(-1) === item;
  }

  readonly collapsedItems = computed(() =>
    this.items().filter((item) => item.display() !== 'visible'),
  );
}

import { HbBreadcrumbComponent, HbBreadcrumbSeparatorDirective } from './breadcrumb.component';
import { HbBreadcrumbEllipsisComponent } from './breadcrumb-ellipsis.component';
import { HbBreadcrumbItemComponent } from './breadcrumb-item.component';

export const HbBreadcrumbImports = [
  HbBreadcrumbComponent,
  HbBreadcrumbItemComponent,
  HbBreadcrumbEllipsisComponent,
  HbBreadcrumbSeparatorDirective,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

export const breadcrumbVariants = cva('text-muted-foreground', {
  variants: {
    size: { xs: 'text-xs', sm: 'text-[0.8125rem]', md: 'text-sm', lg: 'text-base', xl: 'text-lg' },
  },
  defaultVariants: { size: 'md' },
});

export const breadcrumbListVariants = cva('flex items-center gap-1.5 break-words sm:gap-2.5', {
  variants: {
    align: { start: 'justify-start', center: 'justify-center', end: 'justify-end' },
    wrap: { wrap: 'flex-wrap', nowrap: 'flex-nowrap' },
  },
  defaultVariants: { align: 'start', wrap: 'wrap' },
});

export const breadcrumbItemVariants = cva('inline-flex items-center gap-1.5');

export const breadcrumbLinkVariants = cva(
  'inline-flex items-center gap-1.5 transition-colors [&>ng-icon>svg]:size-[1em]',
  {
    variants: {
      current: {
        true: 'font-normal text-foreground',
        false: 'cursor-pointer hover:text-foreground',
      },
    },
    defaultVariants: { current: false },
  },
);

export const breadcrumbSeparatorVariants = cva(
  'inline-flex items-center text-muted-foreground [&>ng-icon>svg]:size-3.5',
);

export const breadcrumbEllipsisVariants = cva(
  'inline-flex items-center justify-center text-muted-foreground [&>ng-icon>svg]:size-4',
);

export type HbBreadcrumbSize = NonNullable<VariantProps<typeof breadcrumbVariants>['size']>;
export type HbBreadcrumbAlign = NonNullable<VariantProps<typeof breadcrumbListVariants>['align']>;
export type HbBreadcrumbWrap = NonNullable<VariantProps<typeof breadcrumbListVariants>['wrap']>;

export * from './breadcrumb.component';
export * from './breadcrumb-item.component';
export * from './breadcrumb-ellipsis.component';
export * from './breadcrumb.variants';
export * from './breadcrumb.imports';

